// create an accessor property; all other attributes default to false.
// dummy getter
var getter = function() {
  return 1;
}
var d1 = {
  get: getter
};
Object.defineProperty(o, "foo", d1);

// now, trying to change the setter should fail, since [[Configurable]]
// on the original property will be false.
var setter = function(x) {};
var desc = {
  set: setter
};
try { function() {
  Object.defineProperty(o, "foo", desc);
}(); console.log("__OK__"); } catch (e) { console.log(e.constructor.name); };
// the property should remain unchanged.
var d2 = Object.getOwnPropertyDescriptor(o, "foo");
console.log(d2.get);
console.log(d2.configurable);
console.log(d2.enumerable);
}

